// Acceder directamente al binario desde el webhook
const binary = $input.first().binary;

// Extraer metadatos del body multipart
const json = $input.first().json.body || {};
const sessionId = json.session_id;
const requestId = json.request_id || sessionId;
const filename = json.filename;

// Validaciones
if (!sessionId) throw new Error('session_id es requerido');
if (!filename) throw new Error('filename es requerido');
if (!binary || Object.keys(binary).length === 0) {
  throw new Error('No hay archivo binario adjunto');
}

// Obtener la clave del binario (normalmente 'file' o 'document')
const binaryKey = Object.keys(binary)[0];
const binaryData = binary[binaryKey];

if (!binaryData) {
  throw new Error(`No se encontró datos binarios en la clave: ${binaryKey}`);
}

// Debug
console.log('Binary key:', binaryKey);
console.log('Binary data available:', !!binaryData);
console.log('Binary size:', binaryData?.dataSize || 'unknown');

// Determinar MIME type por extensión
const ext = filename.split('.').pop().toLowerCase();
const mimeMap = {
  'pdf':  'application/pdf',
  'docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'doc':  'application/msword',
  'xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  'xls':  'application/vnd.ms-excel',
  'csv':  'text/csv',
  'txt':  'text/plain',
  'json': 'application/json',
  'md':   'text/markdown',
  'html': 'text/html',
  'pptx': 'application/vnd.openxmlformats-officedocument.presentationml.presentation'
};

// Si el binario ya tiene mimeType, úsalo; si no, detéctalo por extensión
const mimetype = binaryData?.mimeType || mimeMap[ext] || 'application/octet-stream';

console.log('Final MIME type:', mimetype);
console.log('File extension:', ext);

return [{
  json: {
    session_id: sessionId,
    request_id: requestId,
    filename: filename,
    mimetype: mimetype,
    binary_key: binaryKey,
    debug_binarySize: binaryData?.dataSize || 'not available'
  },
  binary: binary
}];

const sessionStore = $('02 - Buscar store de sesión (BD)1').first().json;
const fileItem = $('01 - Extraer y convertir archivo1').first();

const existingStoreName = sessionStore.store_name || null;

return [{
  json: {
    session_id: fileItem.json.session_id,
    request_id: fileItem.json.request_id,
    filename: fileItem.json.filename,
    mimetype: fileItem.json.mimetype,
    binary_key: fileItem.json.binary_key,
    session_store_name: existingStoreName,
    needs_new_store: existingStoreName === null
  },
  binary: fileItem.binary
}];

// Recuperar datos de ambas ramas posibles
let prev = $('03 - ¿Existe store de sesión?1').first().json;
let storeName = prev.session_store_name;

// Si se creó un store nuevo, usar ese
try {
  const newStoreData = $('06 - Guardar nuevo store en BD1').first().json;
  if (newStoreData && newStoreData.store_name) {
    storeName = newStoreData.store_name;
  }
} catch(e) {
  // La rama del store nuevo no se ejecutó, usar el existente
}

// CRÍTICO: Recuperar el binario del nodo original (antes de cualquier bifurcación)
const binaryData = $('03 - ¿Existe store de sesión?1').first().binary;

if (!binaryData) {
  throw new Error('Binario perdido - no se pudo recuperar de nodo anterior');
}

return [{
  json: {
    session_id: prev.session_id,
    request_id: prev.request_id,
    filename: prev.filename,
    mimetype: prev.mimetype,
    binary_key: prev.binary_key,
    store_name: storeName
  },
  binary: binaryData
}];
